// Stage-Mapping
const STAGES = {
  '874823135': '👤 Lead eingegangen',
  '1810218174': '📞 Setting FollowUp',
  '1810218175': '📅 Setting Call vereinbart',
  '140299275': '🥇 Goldstandard',
  '16380590': '📞 Closing FollowUp',
  '874823137': '🔥 Closing Call 1',
  '70811040': '🔥 Closing Call 2',
  '2622716091': '🔥 Closing Call 3',
  '5055646918': '📧 Rechnungsentwurf',
  '1761746124': '💸 Rechnung',
  '874823138': '💶 Verkauft'
};

const OWNERS = {
  '30037585': 'Dominik',
  '30074150': 'Gülser',
  '30463715': 'Dominic W.',
  '33497731': 'Team'
};

const deals = $('HubSpot: Offene Deals').first().json.results || [];
const wonTotal = $('HubSpot: Verkauft (Total)').first().json.total || 0;

// Stage counts
const stageCounts = {};
const ownerCounts = {};
let todayNew = 0;
let overdueFollowups = 0;
const today = new Date().toISOString().slice(0, 10);
const sevenDaysAgo = new Date(Date.now() - 7 * 86400000).toISOString();

deals.forEach(d => {
  const stage = d.properties.dealstage;
  const owner = d.properties.hubspot_owner_id;

  stageCounts[stage] = (stageCounts[stage] || 0) + 1;

  const ownerName = OWNERS[owner] || 'Andere';
  ownerCounts[ownerName] = (ownerCounts[ownerName] || 0) + 1;

  if ((d.properties.createdate || '').slice(0, 10) === today) todayNew++;

  const lastContact = d.properties.notes_last_contacted;
  if (lastContact && lastContact < sevenDaysAgo) overdueFollowups++;
  if (!lastContact) overdueFollowups++;
});

// Pipeline-Summary
const pipelineLines = Object.entries(STAGES)
  .filter(([id]) => id !== '874823138') // Verkauft separat
  .map(([id, label]) => `${label}: ${stageCounts[id] || 0}`)
  .join(', ');

// Owner-Summary  
const ownerLines = Object.entries(ownerCounts)
  .sort((a, b) => b[1] - a[1])
  .map(([name, count]) => `${name}: ${count}`)
  .join(', ');

// Zusammenfassung
const zusammenfassung = `Pipeline: ${pipelineLines}. ` +
  `Verkauft gesamt: ${wonTotal}. ` +
  `Heute neu: ${todayNew} Leads. ` +
  `Überfällige Follow-ups (>7 Tage): ${overdueFollowups}. ` +
  `Pro Verkäufer: ${ownerLines}.`;

// Output für Supabase
const id = 'kf-hubspot-' + today;

return [{
  json: {
    id,
    pid: null,
    quelle: 'hubspot',
    typ: 'pipeline',
    zusammenfassung,
    rohdaten: { stageCounts, ownerCounts, todayNew, overdueFollowups, wonTotal },
    relevanz: 'hoch',
    created_at: new Date().toISOString(),
    gueltig_bis: today
  }
}];
